REACT_DATA = [
  ("Core","JSX","Basic","Syntactic sugar over React.createElement","Do you still need to import React in React 17+?","No — new JSX transform auto-imports jsx runtime. But still import React to use React.useState etc.","// New JSX transform (React 17+)\nconst el = <div className='box'>Hello</div>;\n// Compiles to:\nimport { jsx as _jsx } from 'react/jsx-runtime';\nconst el = _jsx('div', { className: 'box', children: 'Hello' });"),
  ("Hooks","useState","Basic","Mutable state in function components","Does setState merge or replace state?","Replaces. Use functional update with spread for objects: setState(prev => ({...prev, field: val})).","const [user, setUser] = useState({ name: '', age: 0 });\n// WRONG -- loses age\nsetUser({ name: 'Alice' });\n// CORRECT\nsetUser(prev => ({ ...prev, name: 'Alice' }));\n// Lazy init for expensive default\nconst [data, setData] = useState(() => JSON.parse(localStorage.getItem('data') ?? 'null'));"),
  ("Hooks","useEffect","Intermediate","Run side effects after render","What is the dependency array contract?","All values from component scope used inside useEffect must be in deps. Omitting causes stale closures. ESLint exhaustive-deps enforces this.","// Mount only\nuseEffect(() => { subscribe(); return () => unsubscribe(); }, []);\n// On userId change\nuseEffect(() => { fetchUser(userId); }, [userId]);\n// No array = every render (rarely needed)\nuseEffect(() => { document.title = title; });"),
  ("Hooks","useRef","Intermediate","Mutable ref that persists across renders without causing re-render","useRef vs useState — when to use each?","useRef for: DOM elements, previous values, timers, external instances — anything that doesn't need to trigger UI update. useState for anything that should update UI.","const inputRef = useRef<HTMLInputElement>(null);\nconst countRef  = useRef(0); // track without re-render\nconst prevCount = useRef(count);\n\nuseEffect(() => { prevCount.current = count; });\n\n<input ref={inputRef} />\n<button onClick={() => inputRef.current?.focus()}>Focus</button>"),
  ("Hooks","useMemo & useCallback","Intermediate","Memoize expensive values and stable callbacks","When does memoization actually help?","(1) Expensive computation >1ms. (2) Reference equality matters (object/array passed to memoized child). Premature memoization adds overhead.","const filtered = useMemo(\n  () => items.filter(i => i.active && i.tag === tag),\n  [items, tag]\n);\nconst handleSelect = useCallback(\n  (id: string) => onSelect(id),\n  [onSelect] // stable ref for memo'd children\n);"),
  ("Hooks","useReducer","Intermediate","Complex state with reducer pattern","When to choose useReducer over multiple useStates?","When state transitions are complex, multiple handlers share similar logic, or next state depends on previous. dispatch is stable — pass it instead of multiple callbacks.","type Action = { type: 'inc' } | { type: 'dec' } | { type: 'set'; value: number };\nfunction reducer(state: number, action: Action): number {\n  switch (action.type) {\n    case 'inc': return state + 1;\n    case 'dec': return state - 1;\n    case 'set': return action.value;\n  }\n}\nconst [count, dispatch] = useReducer(reducer, 0);"),
  ("Hooks","useContext","Intermediate","Consume context without prop drilling","Does useContext cause all consumers to re-render on change?","Yes — every consumer re-renders when context value changes, even if they only use an unchanged part. Split contexts by update frequency or use selector pattern.","const ThemeCtx = createContext<Theme>('light');\nconst UserCtx  = createContext<User | null>(null);\n// Split by frequency: theme rarely changes, user might\nfunction useTheme() { return useContext(ThemeCtx); }\nfunction useUser()  { return useContext(UserCtx); }"),
  ("Hooks","useId","Basic","Generate stable unique IDs for accessibility (React 18)","Why not use Math.random() for accessibility IDs?","Math.random() differs between server and client — causes hydration mismatch. useId generates consistent IDs from component tree position.","function TextField({ label }: { label: string }) {\n  const id = useId();\n  return (\n    <>\n      <label htmlFor={id}>{label}</label>\n      <input id={id} />\n    </>\n  );\n}"),
  ("Hooks","useImperativeHandle & forwardRef","Advanced","Expose imperative methods from child to parent","When to use useImperativeHandle?","When parent needs to call methods on child (focus, scroll, validate) — not for sharing state. Prefer props/callbacks when possible.","const Input = forwardRef<{ focus(): void }, Props>((props, ref) => {\n  const inputRef = useRef<HTMLInputElement>(null);\n  useImperativeHandle(ref, () => ({\n    focus: () => inputRef.current?.focus()\n  }));\n  return <input ref={inputRef} {...props} />;\n});\n// Parent:\nconst ref = useRef<{ focus(): void }>(null);\n<Input ref={ref} />\nref.current?.focus();"),
  ("Hooks","Custom hooks","Intermediate","Extract reusable stateful logic","Must custom hooks start with 'use'?","Yes — ESLint react-hooks plugin validates rules-of-hooks based on the 'use' prefix. Without it, hooks inside won't be checked.","function useLocalStorage<T>(key: string, initial: T) {\n  const [value, setValue] = useState<T>(() => {\n    try { return JSON.parse(localStorage.getItem(key)!) ?? initial; }\n    catch { return initial; }\n  });\n  const set = useCallback((v: T) => {\n    setValue(v);\n    localStorage.setItem(key, JSON.stringify(v));\n  }, [key]);\n  return [value, set] as const;\n}"),
  ("Performance","React.memo","Intermediate","Skip re-render if props unchanged","Does React.memo do deep comparison?","No — shallow comparison by reference. Objects/arrays passed as new literals each render bypass memo. Pass custom compareFn as second arg for deep comparison.","const Card = React.memo(\n  ({ user }: { user: User }) => <div>{user.name}</div>,\n  (prev, next) => prev.user.id === next.user.id\n);\n// BROKEN: new object every render -- memo useless\n<Card user={{ name: 'Alice' }} />"),
  ("Performance","Reconciliation & keys","Advanced","React's diffing algorithm for list updates","Why must keys be stable and not array index?","Index keys cause React to reuse DOM nodes incorrectly on reorder/filter. Component state (input values, scroll position) becomes misassigned. Use IDs.","// BAD: index key -- state mismatch on reorder\n{items.map((item, i) => <Input key={i} value={item.value} />)}\n// GOOD: stable unique key\n{items.map(item => <Input key={item.id} value={item.value} />)}"),
  ("Performance","Lazy loading","Intermediate","Code split with React.lazy + Suspense","What is the purpose of Suspense fallback?","Shown while the lazy component's chunk is being downloaded. After the first load it's cached — Suspense only shows on first load or when a new chunk is needed.","const Dashboard = React.lazy(() => import('./Dashboard'));\nconst Settings  = React.lazy(() => import('./Settings'));\n\n<ErrorBoundary>\n  <Suspense fallback={<PageSpinner />}>\n    <Routes>\n      <Route path='/dashboard' element={<Dashboard />} />\n      <Route path='/settings'  element={<Settings />} />\n    </Routes>\n  </Suspense>\n</ErrorBoundary>"),
  ("Patterns","Error Boundaries","Advanced","Catch JS errors in component tree","Why can't function components be error boundaries?","They require componentDidCatch and getDerivedStateFromError class lifecycle methods. Use react-error-boundary library for function component API.","import { ErrorBoundary } from 'react-error-boundary';\n\n<ErrorBoundary\n  fallbackRender={({ error, resetErrorBoundary }) => (\n    <div>\n      <p>Error: {error.message}</p>\n      <button onClick={resetErrorBoundary}>Retry</button>\n    </div>\n  )}\n  onError={(error, info) => logError(error, info)}\n>\n  <App />\n</ErrorBoundary>"),
  ("Patterns","Portals","Advanced","Render into a different DOM node","How do events work with portals?","Event bubbling follows the React component tree, not the DOM tree. A click inside a portal bubbles up through React parents even though DOM-wise it's outside.","function Modal({ onClose, children }: Props) {\n  return createPortal(\n    <div className='overlay' onClick={onClose}>\n      <div className='modal' onClick={e => e.stopPropagation()}>\n        {children}\n      </div>\n    </div>,\n    document.getElementById('portal-root')!\n  );\n}"),
  ("Patterns","Compound components","Advanced","Components sharing implicit state via context","What problem do compound components solve?","API flexibility — consumers control layout and composition rather than configuring everything through props.","const TabsCtx = createContext<{ active: number; setActive: (n: number) => void } | null>(null);\nfunction Tabs({ children }: { children: ReactNode }) {\n  const [active, setActive] = useState(0);\n  return <TabsCtx.Provider value={{ active, setActive }}>{children}</TabsCtx.Provider>;\n}\nTabs.Tab = function({ index, children }: { index: number; children: ReactNode }) {\n  const ctx = useContext(TabsCtx)!;\n  return <button aria-selected={ctx.active === index} onClick={() => ctx.setActive(index)}>{children}</button>;\n};"),
  ("Patterns","Render props","Intermediate","Pass function as prop to share behaviour","Are render props still used in modern React?","Less common — custom hooks replaced most render prop use cases. Still useful for headless UI libraries (Downshift, react-table) where consumer fully controls rendering.","// Render prop\nfunction DataFetcher<T>({ url, render }: { url: string; render: (data: T) => ReactNode }) {\n  const [data, setData] = useState<T | null>(null);\n  useEffect(() => { fetch(url).then(r => r.json()).then(setData); }, [url]);\n  return data ? render(data) : <Spinner />;\n}\n<DataFetcher url='/api/users' render={users => <UserList users={users} />} />"),
  ("Patterns","Higher-Order Components","Intermediate","HOC wraps component to add behaviour","HOC vs custom hook — which to use?","Custom hooks for reusing stateful logic (preferred). HOC for cross-cutting concerns that need to wrap JSX (legacy code, some libraries). HOCs add wrapper divs and complicate DevTools.","function withAuth<P>(Component: ComponentType<P>) {\n  return function AuthGuard(props: P) {\n    const { user } = useAuth();\n    if (!user) return <Navigate to='/login' />;\n    return <Component {...props} />;\n  };\n}\nconst ProtectedPage = withAuth(Dashboard);"),
  ("Concurrent","useTransition","Advanced","Mark state updates as non-urgent (React 18)","What does isPending give you?","A boolean true while deferred update is pending. Use to show loading indicator without blocking the input from updating.","const [query, setQuery] = useState('');\nconst [results, setResults] = useState([]);\nconst [isPending, startTransition] = useTransition();\n\nfunction handleSearch(q: string) {\n  setQuery(q); // urgent: update input\n  startTransition(() => {\n    setResults(filter(items, q)); // non-urgent: can be interrupted\n  });\n}"),
  ("Concurrent","useDeferredValue","Advanced","Defer a value until browser is idle","useTransition vs useDeferredValue?","useTransition: you control which update is deferred (wrap setState). useDeferredValue: you defer a value you receive as prop/context — useful when you don't own the state setter.","const deferredQuery = useDeferredValue(query);\n// deferredQuery lags behind query\n// Show stale content while new results compute\n<div style={{ opacity: deferredQuery !== query ? 0.5 : 1 }}>\n  <Results query={deferredQuery} />\n</div>"),
  ("Tricky","Batching (React 18)","Tricky","All state updates batched in React 18","What changed about batching in React 18?","React 17: batching only in React event handlers. React 18: automatic batching everywhere — setTimeout, promises, native events. Use flushSync() to opt out.","// React 18: both updates = 1 re-render\nsetTimeout(() => {\n  setA(1);\n  setB(2); // batched!\n}, 0);\n// Opt out:\nimport { flushSync } from 'react-dom';\nflushSync(() => setA(1)); // immediate re-render\nflushSync(() => setB(2)); // another re-render"),
  ("Tricky","Stale closures","Tricky","Event handlers capture outdated state values","How do you fix stale state in event handlers?","Functional setState: setState(prev => prev + 1). useRef to track latest: ref.current = state, read ref.current in handler.","// BUG: count always 0 in handler\nuseEffect(() => {\n  window.addEventListener('click', () => {\n    console.log(count); // stale!\n    setCount(count + 1); // BUG: always 1\n  });\n}, []);\n// FIX 1: functional update\nsetCount(c => c + 1);\n// FIX 2: ref\nconst countRef = useRef(count);\ncountRef.current = count;\n// Use countRef.current in handler"),
  ("Tricky","StrictMode double-invoke","Tricky","React 18 StrictMode mounts/unmounts/remounts in dev","Why does useEffect run twice in development?","StrictMode intentionally remounts to surface missing cleanup. If effect has side effects that aren't cleaned up, you'll see doubled API calls. Fix: add proper cleanup.","useEffect(() => {\n  const sub = eventBus.subscribe(handler);\n  return () => sub.unsubscribe(); // REQUIRED cleanup\n}, []);\n// Only in development -- production mounts once"),
  ("Tricky","Reconciliation & object identity","Tricky","New object references cause unnecessary re-renders","Why does passing object literals as props break memo?","Every render creates a new object — reference changes even if values are same. useMemo/useCallback to stabilize references.","// Re-renders Card every time even with React.memo\n<Card style={{ color: 'red' }} onClick={() => handleClick(id)} />\n// Stable:\nconst style    = useMemo(() => ({ color: 'red' }), []);\nconst onClick  = useCallback(() => handleClick(id), [id]);\n<Card style={style} onClick={onClick} />"),
]

RN_DATA = [
  ("Core","Core components","Basic","View, Text, TextInput, ScrollView, FlatList, Image, Pressable","When to use ScrollView vs FlatList?","ScrollView renders all children at once — terrible for long lists. FlatList virtualizes — only renders visible items. Use FlatList for >20 items.","<FlatList\n  data={items}\n  keyExtractor={item => item.id}\n  renderItem={({ item }) => <Row item={item} />}\n  initialNumToRender={10}\n  maxToRenderPerBatch={5}\n  windowSize={5}\n/>"),
  ("Core","StyleSheet","Basic","JS object styling — camelCase, no units","Why StyleSheet.create over plain objects?","Validates in dev, serializes style IDs across the JS-Native bridge instead of full objects — less data transfer. Styles are registered once and cached.","const s = StyleSheet.create({\n  container: { flex: 1, padding: 16, backgroundColor: '#fff' },\n  title:     { fontSize: 20, fontWeight: '700', color: '#0f172a' },\n  // No 'px' — values are dp (density-independent pixels)\n});"),
  ("Core","Flexbox in RN","Intermediate","Same as web Flexbox but different defaults","Key differences from web Flexbox?","flexDirection defaults to 'column'. flex:1 fills available space. No display:grid — Flexbox is the only layout system. No shorthand like 1rem — numeric dp values only.","<View style={{ flex:1, flexDirection:'row', gap:8, flexWrap:'wrap' }}>\n  <View style={{ flex:1, minWidth:120 }} />\n  <View style={{ flex:2, minWidth:200 }} />\n</View>"),
  ("Core","Pressable","Intermediate","Flexible touch handler replacing TouchableOpacity","Pressable vs TouchableOpacity?","Pressable is more flexible: render prop for pressed state, hitSlop, unstable_pressDelay. TouchableOpacity is simpler but Pressable is preferred in new code.","<Pressable\n  onPress={handlePress}\n  onLongPress={handleLong}\n  hitSlop={8}\n  style={({ pressed }) => ([\n    s.btn,\n    pressed && { opacity: 0.7 }\n  ])}\n>\n  {({ pressed }) => <Text>{pressed ? 'Holding...' : 'Press me'}</Text>}\n</Pressable>"),
  ("Core","SafeAreaView","Basic","Avoids notch, status bar, home indicator","Why not just add padding manually?","Device dimensions and inset sizes vary significantly across models and platforms. SafeAreaView and the useSafeAreaInsets hook from react-native-safe-area-context handle all cases.","import { SafeAreaView } from 'react-native-safe-area-context';\n// or for fine-grained:\nimport { useSafeAreaInsets } from 'react-native-safe-area-context';\nfunction Screen() {\n  const insets = useSafeAreaInsets();\n  return <View style={{ paddingTop: insets.top }}>...</View>;\n}"),
  ("Core","Modal","Basic","Overlay modal dialog","What is the transparent prop on Modal?","transparent:true makes background transparent — you see the content behind. Use a semi-opaque View inside for overlay effect. Without it, Modal has an opaque background.","<Modal visible={show} transparent animationType='fade' onRequestClose={onClose}>\n  <Pressable style={s.overlay} onPress={onClose}>\n    <View style={s.sheet}>\n      <Text>Modal content</Text>\n      <Button title='Close' onPress={onClose} />\n    </View>\n  </Pressable>\n</Modal>"),
  ("Navigation","React Navigation","Intermediate","Stack, Tab, Drawer navigators","navigate vs push vs replace?","navigate: go to screen (no duplicate if already in stack). push: always adds new instance. replace: swap current screen. goBack: go to previous.","// Setup\nconst Stack = createNativeStackNavigator();\n// Usage in screen\nnavigation.navigate('Profile', { userId: 42 });\nnavigation.push('Profile', { userId: 43 }); // new instance\nnavigation.replace('Home'); // replace current\nnavigation.goBack();\nnavigation.popTo('Dashboard'); // pop to specific screen"),
  ("Navigation","Passing params","Intermediate","Pass data between screens","How do you type navigation params?","Define RootStackParamList type and use it with useNavigation<NavigationProp<...>> and useRoute<RouteProp<...>>.","type RootStack = {\n  Home: undefined;\n  Profile: { userId: number; readOnly?: boolean };\n};\n// In screen:\nconst route = useRoute<RouteProp<RootStack, 'Profile'>>();\nconst { userId } = route.params;\nconst nav = useNavigation<NativeStackNavigationProp<RootStack>>();"),
  ("Navigation","Deep linking","Advanced","URL schemes and universal links","URL scheme vs universal link?","URL scheme (myapp://): any app can claim it. Universal link (https://): verified via AASA file on server — can't be spoofed, works as web URL too.","// app.json\n{ \"expo\": { \"scheme\": \"devquiz\",\n  \"intentFilters\": [{\n    \"action\": \"VIEW\",\n    \"data\": [{ \"scheme\": \"https\", \"host\": \"devquiz.app\" }],\n    \"category\": [\"BROWSABLE\", \"DEFAULT\"]\n  }] } }\n// Linking.getInitialURL() for cold start\n// Linking.addEventListener for warm start"),
  ("Performance","FlatList optimization","Advanced","Virtualized list tuning","What is getItemLayout and when is it required?","Pre-computes item positions — enables scrollToIndex without rendering all intermediary items. Required for scrollToIndex and scrollToOffset to work reliably on large lists.","<FlatList\n  data={data}\n  getItemLayout={(_, index) => ({ length: ITEM_HEIGHT, offset: ITEM_HEIGHT * index, index })}\n  removeClippedSubviews\n  maxToRenderPerBatch={10}\n  updateCellsBatchingPeriod={50}\n  windowSize={5}\n  keyExtractor={item => item.id}\n/>"),
  ("Performance","Animations — Animated API","Intermediate","Declarative animations on JS thread","When to use useNativeDriver?","useNativeDriver:true runs animation on native UI thread — never drops frames. Only works for transform and opacity. For other properties (width, backgroundColor) must use JS thread.","const anim = useRef(new Animated.Value(0)).current;\nAnimated.spring(anim, {\n  toValue: 1,\n  useNativeDriver: true, // ALWAYS use if possible\n  bounciness: 8,\n}).start();\n<Animated.View style={{ opacity: anim, transform: [{ scale: anim }] }} />"),
  ("Performance","Reanimated 3","Advanced","UI-thread animations with worklets","What is a worklet?","A JS function marked with 'worklet' that runs on the UI thread. Shared values bridge JS↔UI without going through the bridge.","import { useSharedValue, useAnimatedStyle, withSpring, withTiming } from 'react-native-reanimated';\n\nconst offset = useSharedValue(0);\nconst animStyle = useAnimatedStyle(() => ({\n  transform: [{ translateX: offset.value }]\n}));\n// Trigger from JS thread\noffset.value = withSpring(100);\n<Animated.View style={animStyle} />"),
  ("Performance","Hermes engine","Intermediate","Optimised JS engine for React Native","Hermes advantages?","Precompiled bytecode (faster cold start), lower memory, built-in debugging. Default since RN 0.70. Disadvantage: slightly behind V8 on some language features (mostly caught up).","// android/app/build.gradle\nproject.ext.react = [\n  enableHermes: true // default since 0.70\n]\n// iOS: Podfile\nuse_hermes!"),
  ("Platform","Platform-specific","Intermediate","Platform.OS and file extensions","Platform.select vs file extensions?","Platform.select: runtime conditional — both platforms bundled. File extensions (.ios.tsx/.android.tsx): build-time resolution — smaller bundle, true separation.","// Runtime: both platforms in bundle\nconst shadow = Platform.select({\n  ios:     { shadowColor: '#000', shadowOpacity: 0.2, shadowRadius: 4 },\n  android: { elevation: 4 }\n});\n// Build-time: separate files\n// Button.ios.tsx\n// Button.android.tsx\nimport Button from './Button'; // Metro picks correct file"),
  ("Platform","Permissions","Intermediate","Request device permissions at runtime","Why do permissions differ between iOS and Android?","iOS: must declare in Info.plist AND request at runtime. Android: declare in AndroidManifest.xml AND request at runtime for dangerous permissions (camera, location, contacts).","import { check, request, PERMISSIONS, RESULTS } from 'react-native-permissions';\n\nasync function requestCamera() {\n  const result = await request(\n    Platform.OS === 'ios'\n      ? PERMISSIONS.IOS.CAMERA\n      : PERMISSIONS.ANDROID.CAMERA\n  );\n  return result === RESULTS.GRANTED;\n}"),
  ("Platform","Linking & App State","Intermediate","Open URLs and track app lifecycle","AppState values?","active: foreground. background: minimized/home screen. inactive: iOS only — transitioning between states (call comes in).","import { AppState, Linking } from 'react-native';\nuseEffect(() => {\n  const sub = AppState.addEventListener('change', state => {\n    if (state === 'active') refreshData();\n  });\n  return () => sub.remove();\n}, []);\n// Open URL\nawait Linking.openURL('https://devquiz.app');\nawait Linking.openSettings(); // device settings"),
  ("Storage","AsyncStorage","Intermediate","Async key-value storage","AsyncStorage limitations?","Not encrypted, ~6MB Android default, async only, no querying. For encryption: expo-secure-store. For large data: expo-sqlite or WatermelonDB.","import AsyncStorage from '@react-native-async-storage/async-storage';\ntry {\n  await AsyncStorage.setItem('user', JSON.stringify(user));\n  const raw = await AsyncStorage.getItem('user');\n  const data = raw ? JSON.parse(raw) : null;\n  await AsyncStorage.multiRemove(['user', 'token']);\n} catch (e) { console.error('Storage error:', e); }"),
  ("Tricky","KeyboardAvoidingView","Tricky","Layout adjustment when keyboard appears","Why does KAV behave differently on iOS vs Android?","Android resizes window via windowSoftInputMode=adjustResize — KAV often not needed. iOS overlays keyboard without resize — KAV required with behavior='padding'.","<KeyboardAvoidingView\n  style={{ flex: 1 }}\n  behavior={Platform.OS === 'ios' ? 'padding' : 'height'}\n  keyboardVerticalOffset={Platform.OS === 'ios' ? 88 : 0}\n>\n  <ScrollView keyboardShouldPersistTaps='handled'>\n    <TextInput ... />\n  </ScrollView>\n</KeyboardAvoidingView>"),
  ("Tricky","Bridge & New Architecture","Advanced","JS↔Native communication","New Architecture: what changed?","Fabric: synchronous layout, concurrent features. TurboModules: JSI-based direct C++ calls (no serialization). Codegen: type-safe native bridge. Default in RN 0.76+.","// Check new arch\nimport { TurboModuleRegistry } from 'react-native';\nconst native = TurboModuleRegistry.getEnforcing<Spec>('MyModule');\n// JSI: synchronous call\nnative.syncMethod(); // no bridge roundtrip"),
  ("Tricky","Metro bundler quirks","Intermediate","RN bundler — not Webpack","Metro limitations vs Webpack?","No tree shaking (bundles everything imported). Different module resolution. Limited plugin ecosystem. But: very fast incremental builds, built-in HMR, supports iOS/Android simultaneously.","// metro.config.js\nconst { getDefaultConfig } = require('@react-native/metro-config');\nmodule.exports = (() => {\n  const config = getDefaultConfig(__dirname);\n  config.resolver.sourceExts.push('cjs');\n  config.transformer.babelTransformerPath =\n    require.resolve('react-native-svg-transformer');\n  return config;\n})();"),
  ("Tricky","Image caching","Tricky","Image loading and caching in React Native","Why do images flicker on re-render?","No built-in memory cache for <Image> from remote URLs. Use FastImage (react-native-fast-image) which uses SDWebImage (iOS) and Glide (Android) with proper disk+memory caching.","import FastImage from 'react-native-fast-image';\n<FastImage\n  source={{\n    uri: user.avatar,\n    priority: FastImage.priority.high,\n    cache: FastImage.cacheControl.immutable\n  }}\n  style={{ width: 48, height: 48, borderRadius: 24 }}\n  resizeMode={FastImage.resizeMode.cover}\n/>"),
]

NEXT_DATA = [
  ("Rendering","SSR vs SSG vs ISR vs CSR","Basic","Four rendering strategies","What is ISR?","ISR: static HTML built at build time, regenerated in background after revalidate seconds. Best for semi-static content. Combines SSG speed with near-real-time data.","// App Router: fetch with revalidate = ISR\nconst data = await fetch(url, { next: { revalidate: 60 } }).then(r => r.json());\n// Force static\nexport const dynamic = 'force-static';\n// Force dynamic (SSR)\nexport const dynamic = 'force-dynamic';"),
  ("Rendering","Server Components","Advanced","React Server Components — run on server, no client JS","Can Server Components use hooks?","No. Add 'use client' for hooks. Server Components can import Client Components. Client Components cannot import Server Components directly (pass as children/props instead).","// Default: Server Component\nasync function UserList() {\n  const users = await db.query('SELECT * FROM users');\n  return <ul>{users.map(u => <li key={u.id}>{u.name}</li>)}</ul>;\n}\n// Client Component\n'use client';\nfunction Counter() {\n  const [n, setN] = useState(0);\n  return <button onClick={() => setN(n+1)}>{n}</button>;\n}"),
  ("Rendering","Streaming & Suspense","Advanced","Progressive HTML streaming from server","How does streaming improve LCP?","First byte arrives immediately. Important content (hero, nav) renders without waiting for slow data fetches. Slow sections (recommendations, related posts) stream in separately.","// loading.tsx auto-creates Suspense boundary\nexport default function Loading() { return <PageSkeleton />; }\n// Manual Suspense for granular control\n<>\n  <Hero />  {/* immediate */}\n  <Suspense fallback={<RecoSkeleton />}>\n    <Recommendations /> {/* streams separately */}\n  </Suspense>\n</>"),
  ("Routing","App Router file conventions","Intermediate","page, layout, template, loading, error, not-found","layout vs template?","layout: persistent state preserved on navigation (doesn't remount). template: creates new instance per navigation (remounts). Use template for animations or per-route state reset.","app/\n  layout.tsx       -- root shell (persistent)\n  page.tsx         -- /\n  dashboard/\n    layout.tsx     -- sidebar (persistent)\n    loading.tsx    -- Suspense fallback\n    error.tsx      -- Error boundary\n    not-found.tsx  -- 404 for segment\n    page.tsx       -- /dashboard"),
  ("Routing","Dynamic routes","Intermediate","[param], [...slug], [[...slug]] segments","Difference between [...slug] and [[...slug]]?","[...slug]: required — route only matches if segment has value. [[...slug]]: optional — also matches the segment without any slug (e.g., /blog matches app/blog/[[...slug]]/page.tsx).","// app/blog/[slug]/page.tsx\nexport default function Post({ params }: { params: { slug: string } }) {}\n// app/docs/[...path]/page.tsx  -- /docs/a/b/c\nexport default function Doc({ params }: { params: { path: string[] } }) {}"),
  ("Routing","Route groups","Intermediate","(folder) groups routes without affecting URL","What are route groups used for?","Organize routes without URL segments: different layouts for auth vs app, separate loading/error states per group.","app/\n  (marketing)/\n    layout.tsx  -- marketing layout (no header)\n    page.tsx    -- /\n    about/page.tsx  -- /about\n  (app)/\n    layout.tsx  -- app shell with sidebar\n    dashboard/page.tsx  -- /dashboard"),
  ("Routing","Middleware","Advanced","Run code at the edge before request","What can middleware NOT do?","No Node.js APIs (fs, database drivers) — runs in Edge runtime. No JSX. Size limit on imports. Use for: auth redirects, geolocation headers, A/B testing, rate limiting.","// middleware.ts (root)\nimport { NextResponse } from 'next/server';\nimport { verifyJWT } from '@/lib/auth';\nexport function middleware(req) {\n  const token = req.cookies.get('token')?.value;\n  if (!token && req.nextUrl.pathname.startsWith('/app')) {\n    return NextResponse.redirect(new URL('/login', req.url));\n  }\n}\nexport const config = { matcher: ['/app/:path*'] };"),
  ("Data","Route handlers","Intermediate","API routes in App Router","What HTTP methods are supported?","GET, POST, PUT, PATCH, DELETE, HEAD, OPTIONS. GET is cached by default; mutation methods are not. Add dynamic = 'force-dynamic' to opt GET out of cache.","// app/api/posts/route.ts\nexport async function GET(req: NextRequest) {\n  const { searchParams } = new URL(req.url);\n  const page = Number(searchParams.get('page') ?? 1);\n  return NextResponse.json(await getPosts(page));\n}\nexport async function POST(req: NextRequest) {\n  const body = await req.json();\n  const post = await createPost(body);\n  return NextResponse.json(post, { status: 201 });\n}"),
  ("Data","Server Actions","Advanced","Async server functions called from client","Are Server Actions CSRF-safe?","Yes — Next.js adds origin checking and a unique action ID per action. Can't be called from arbitrary origins.","'use server';\nasync function deletePost(formData: FormData) {\n  const id = formData.get('id') as string;\n  await db.posts.delete(id);\n  revalidatePath('/posts');\n}\n// With useActionState (React 19)\nconst [state, action, pending] = useActionState(createPost, null);"),
  ("Data","Caching layers","Advanced","Request memoization, Data cache, Full Route Cache, Router Cache","How do you bust the Data cache after a mutation?","revalidatePath('/posts') invalidates Full Route Cache for that path. revalidateTag('posts') invalidates all fetches tagged with 'posts'. Both run inside Server Actions or Route Handlers only.","// Tag fetches\nawait fetch(url, { next: { tags: ['posts'] } });\n// Bust by tag\nimport { revalidateTag, revalidatePath } from 'next/cache';\nrevalidateTag('posts'); // all tagged fetches\nrevalidatePath('/posts'); // full route cache"),
  ("Performance","Image optimization","Intermediate","next/image — lazy loading, sizing, format conversion","What does priority do?","Adds <link rel=preload> and disables lazy loading. Use for LCP (above-fold) images only. All other images are lazy by default.","import Image from 'next/image';\n<Image\n  src='/hero.jpg'\n  alt='Hero'\n  width={1200}\n  height={600}\n  priority  // LCP image -- preload\n  sizes='(max-width:768px) 100vw, 50vw'\n  quality={85}\n/>"),
  ("Performance","Font optimization","Intermediate","next/font — self-hosted, zero CLS","How does next/font prevent layout shift?","Generates CSS size-adjust and ascent-override to match fallback font metrics exactly. Self-hosts at build time — no external requests during page load.","import { Inter, JetBrains_Mono } from 'next/font/google';\nconst inter = Inter({ subsets: ['latin'], variable: '--font-sans' });\nconst mono  = JetBrains_Mono({ subsets: ['latin'], variable: '--font-mono' });\nexport default function RootLayout({ children }) {\n  return <html className={`${inter.variable} ${mono.variable}`}>{children}</html>;\n}"),
  ("Performance","Script optimization","Intermediate","next/script with loading strategies","What is the difference between beforeInteractive, afterInteractive, and lazyOnload?","beforeInteractive: blocks page (critical scripts only). afterInteractive: after hydration (analytics). lazyOnload: when browser is idle (chat widgets, non-critical).","import Script from 'next/script';\n// Analytics: after hydration\n<Script src='analytics.js' strategy='afterInteractive' />\n// Chat widget: idle time\n<Script src='chat.js' strategy='lazyOnload' onLoad={() => initChat()} />"),
  ("SEO","Metadata API","Intermediate","Export metadata object or generateMetadata function","How do you generate dynamic metadata?","Export async generateMetadata function from page.tsx. It receives params — use it to fetch data for title, description, og tags.","// Static metadata\nexport const metadata = {\n  title: 'DevQuiz',\n  description: 'Practice coding interview questions',\n  openGraph: { images: ['/og.png'] },\n};\n// Dynamic metadata\nexport async function generateMetadata({ params }) {\n  const post = await getPost(params.slug);\n  return { title: post.title, description: post.excerpt };\n}"),
  ("Advanced","Parallel routes","Advanced","Render multiple pages in same layout (@slot)","When do you use parallel routes?","Dashboards with independent sections, modals that show inline with background page, tabs that navigate independently.","app/\n  layout.tsx  -- renders {children} {analytics} {team}\n  @analytics/\n    page.tsx   -- /dashboard/analytics slot\n  @team/\n    page.tsx   -- /dashboard/team slot\n  page.tsx     -- main content"),
  ("Advanced","Intercepting routes","Advanced","Show route in modal while keeping background","How do intercepting routes work?","(.) same level, (..) one level up, (...) root. When intercepted route is navigated via Link, shows as modal. Direct URL navigation shows full page.","app/\n  @modal/\n    (.)photo/[id]/page.tsx  -- intercepted: modal\n  photo/[id]/page.tsx        -- direct: full page\n  page.tsx\n  layout.tsx  -- renders {children} {modal}"),
  ("Tricky","use client boundary","Tricky","'use client' marks Client Component boundary","Does 'use client' make ALL imports client-side?","Yes — all imports in a 'use client' file become Client Components. But children/props can still be Server Components — they're passed through, not imported.","// ClientWrapper.tsx\n'use client';\nfunction Drawer({ children }: { children: ReactNode }) {\n  const [open, setOpen] = useState(false);\n  return <div>{open && children}</div>;\n}\n// page.tsx (Server)\n<Drawer>\n  <ServerDataComponent /> {/* server-rendered */}\n</Drawer>"),
  ("Tricky","Environment variables","Intermediate","Server vs client env var exposure","Why does NEXT_PUBLIC_ prefix matter?","Only NEXT_PUBLIC_ vars are bundled to client. Others are server-only. Warning: if you pass a server env var as prop to a Client Component, it leaks to the client bundle.","# .env.local\nDATABASE_URL=postgres://...   # server only\nNEXT_PUBLIC_API=https://...   # client + server\n// Usage\nprocess.env.DATABASE_URL       // server only\nprocess.env.NEXT_PUBLIC_API    // anywhere"),
  ("Tricky","generateStaticParams","Intermediate","Pre-build dynamic route pages at build time","What happens to paths not in generateStaticParams?","dynamicParams=true (default): generate on demand. dynamicParams=false: 404 for unknown slugs.","export async function generateStaticParams() {\n  const posts = await getPosts();\n  return posts.map(p => ({ slug: p.slug }));\n}\nexport const dynamicParams = false; // 404 unknown\nexport const revalidate = 3600;     // regenerate hourly"),
  ("Config","next.config.js","Intermediate","Configure Next.js build and runtime","What are rewrites vs redirects?","rewrites: proxy a URL to another path (URL stays same). redirects: send browser to new URL (URL changes, 301/302). Rewrites good for API proxying.","// next.config.ts\nimport type { NextConfig } from 'next';\nconst config: NextConfig = {\n  images: { remotePatterns: [{ hostname: 'cdn.devquiz.app' }] },\n  async rewrites() {\n    return [{ source: '/api/:path*', destination: 'https://api.devquiz.app/:path*' }];\n  },\n  async redirects() {\n    return [{ source: '/old', destination: '/new', permanent: true }];\n  },\n};\nexport default config;"),
]
